Use MSTest's `[DataTestMethod]` / `[DataRow]` to make these data-driven. Most of your cases collapse into two methods:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow(null, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("", "Input cannot be empty", DisplayName = "Empty string")]
    [DataRow("   ", "Input cannot be empty", DisplayName = "Whitespace only")]
    [DataRow("ab", "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", "Input contains invalid characters", DisplayName = "Special chars")]
    public void Validate_InvalidInput_ReturnsFalse(string? input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    [DataTestMethod]
    [DataRow("abc", DisplayName = "Min length")]
    [DataRow("hello-world", DisplayName = "Typical input")]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    // Computed inputs can't be DataRow constants — use DynamicData instead
    [DataTestMethod]
    [DynamicData(nameof(BoundaryLengthCases), DynamicDataSourceType.Method)]
    public void Validate_BoundaryLength_ReturnsExpected(
        string input, bool expectedValid, string? expectedError)
    {
        var result = _validator.Validate(input);
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object?[]> BoundaryLengthCases()
    {
        yield return [new string('a', 255), true, null];
        yield return [new string('x', 256), false, "Input must not exceed 255 characters"];
    }
}
```

**Key points:**

- **`[DataRow]`** — each attribute adds a test case; no new method needed for simple constant inputs.
- **`[DynamicData]`** — covers cases needing computed values (like `new string(...)`) that can't be compile-time constants.
- **`[TestInitialize]`** — removes the repeated `new InputValidator()` setup.
- Each case still shows as a separate entry in Test Explorer thanks to `DisplayName`.
